import { HORIZONTAL_ALIGN, RIGHT_ALIGN, LEFT_ALIGN, TOP_ALIGN, BOTTOM_ALIGN } from '../../../core/align-constants';
import { ORDINAL_DATATYPE } from '../../../core/datatype-constants';
import { d3_ascending } from '../../../core/d3-constants';
import { d3_values } from '../../../utils/zcutils';
import { getActiveDiscreteDomain } from '../../../legend/colorband/colorband-brush-tooltip-content';

export function getSliderMarkerPosition(scale, brushScale, config, bound, align) {
    let { hAlign, vAlign } = config,
        //
        sizeBandWidth = scale.bandwidth ? scale.bandwidth() : 0,
        posBandWidth = brushScale.bandwidth ? brushScale.bandwidth() : 0,
        //
        w = bound.width,
        h = bound.height,
        //
        r = d => scale(d) + sizeBandWidth / 2,
        x,
        y;

    if (align.layout === HORIZONTAL_ALIGN) {
        x = d => brushScale(d) + posBandWidth / 2;
        if (vAlign === TOP_ALIGN) {
            y = d => r(d) / 2;
        } else if (vAlign === BOTTOM_ALIGN) {
            y = d => h - r(d) / 2;
        } else {
            y = d => h / 2;
        }
    } else {
        y = d => brushScale(d) + posBandWidth / 2;
        if (hAlign === LEFT_ALIGN) {
            x = d => r(d) / 2;
        } else if (hAlign === RIGHT_ALIGN) {
            x = d => w - r(d) / 2;
        } else {
            x = d => w / 2;
        }
    }

    return { x, y, r };
}

export function getHandleData(options, point, strictReverse) {
    let { ranges, reversed, config, sizeScale: scale, datatype: dataType, singleDomainContinuous } = options,
        filterRange = config.filter.range,
        data;

    if (filterRange) {
        point = point || (reversed ? d3_values(filterRange).reverse() : filterRange);
    }

    if (singleDomainContinuous) {
        return scale.domain();
    }

    if (point) {
        if (dataType === ORDINAL_DATATYPE) {
            let extentData = [point[0], point[point.length - 1]];
            data = reversed ? d3_values(extentData).reverse() : extentData;
        } else if (ranges && ranges.length) {
            data = getActiveDiscreteDomain(d3_values(point).sort(d3_ascending), ranges);
        } else {
            data = strictReverse ? d3_values(point).reverse() : point;
        }

        if (ranges && ranges.length && reversed) {
            data = d3_values(data).reverse();
        }

        return data;
    } else {
        let scale_domain = scale.domain(),
            _extentData = [scale_domain[0], scale_domain[scale_domain.length - 1]],
            data = reversed ? d3_values(_extentData).reverse() : _extentData;

        return data;
    }
}
